const VOWELS = new Set(['a', 'e', 'i', 'o', 'u']);

function isVowel(char) {
    return VOWELS.has(char);
}

function solve(s) {
    // 1. Analysis Phase: Calculate frequencies and first indices
    const frequencies = {};
    const firstIndices = {};

    for (let i = 0; i < s.length; i++) {
        const char = s[i];
        if (isVowel(char)) {
            // Calculate frequency
            frequencies[char] = (frequencies[char] || 0) + 1;

            // Record first index
            if (firstIndices[char] === undefined) {
                firstIndices[char] = i;
            }
        }
    }

    // Get unique vowels present and convert to an array
    const uniqueVowels = Object.keys(frequencies);

    // 2. Sorting Phase: Sort the unique vowels based on criteria
    // Primary: Frequency (Descending)
    // Secondary: First Index (Ascending)
    uniqueVowels.sort((a, b) => {
        const freqA = frequencies[a];
        const freqB = frequencies[b];

        // Compare frequencies (Descending: B - A)
        if (freqA !== freqB) {
            return freqB - freqA;
        }

        // Frequencies are equal, compare first indices (Ascending: A - B)
        const indexA = firstIndices[a];
        const indexB = firstIndices[b];
        return indexA - indexB;
    });

    // 3. Construct the replacement sequence
    const replacementSequence = [];
    for (const vowel of uniqueVowels) {
        const count = frequencies[vowel];
        for (let i = 0; i < count; i++) {
            replacementSequence.push(vowel);
        }
    }

    // 4. Replacement Phase: Reconstruct the string
    let sequenceIndex = 0;
    const result = [];

    for (let i = 0; i < s.length; i++) {
        const char = s[i];
        if (isVowel(char)) {
            // Replace with the next character from the sorted sequence
            result.push(replacementSequence[sequenceIndex]);
            sequenceIndex++;
        } else {
            // Keep consonant as is
            result.push(char);
