use std::collections::HashMap;

fn is_vowel(c: char) -> bool {
    matches!(c, 'a' | 'e' | 'i' | 'o' | 'u')
}

fn solve(s: String) -> String {
    // 1. Analysis Phase: Calculate frequencies and first indices

    // Map stores: Vowel -> (Frequency, First Index)
    let mut vowel_data: HashMap<char, (usize, usize)> = HashMap::new();

    for (i, c) in s.chars().enumerate() {
        if is_vowel(c) {
            let entry = vowel_data.entry(c).or_insert((0, i));

            // Increment frequency
            entry.0 += 1;

            // Record first index only if it hasn't been recorded yet (which is handled by or_insert setting it to i initially)
            // Since we iterate sequentially, the first time we encounter a vowel, its index is stored.
            // We don't need explicit check here if we rely on the initial assignment, but ensuring it's the minimum index is safest.
            // For this specific logic, the initial assignment via or_insert works correctly because we iterate in increasing order of i.
        }
    }

    // Convert HashMap entries into a vector for sorting
    // Item structure: (char, frequency, first_index)
    let mut vowels_to_sort: Vec<(char, usize, usize)> = Vec::new();
    for (vowel, &(freq, first_idx)) in vowel_data.iter() {
        vowels_to_sort.push((*vowel, freq, first_idx));
    }

    // 2. Sorting Phase: Sort the unique vowels
    // Primary: Frequency (Descending)
    // Secondary: First Index (Ascending)
    vowels_to_sort.sort_by(|a, b| {
        let freq_a = a.1;
        let freq_b = b.1;

        // Compare frequencies (Descending: B vs A)
        if freq_a != freq_b {
            freq_b.cmp(&freq_a)
        } else {
            // Frequencies are equal, compare first indices (Ascending: A vs B)
            a.2.cmp(&b.2)
        }
    });

    // 3. Construct the replacement sequence
    let mut replacement_sequence: Vec<char> = Vec::new();
    for (vowel, count, _) in vowels_to_sort {
        for _ in 0..count {
            replacement_sequence.push(vowel);
        }
    }

    // 4. Replacement Phase: Reconstruct the string
    let mut result_chars: Vec<char> = Vec::with_capacity(s.len());
    let mut seq_index = 0;

