        if is_vowel(c) {
            // Replace with the next character from the sorted sequence
            // Since we ensured the total count matches, this access is safe.
            result_chars.push(replacement_sequence[seq_index]);
            seq_index += 1;
        } else {
            // Keep consonant as is
            result_chars.push(c);
        }
    }

    result_chars.into_iter().collect()
}

