fn solve(s: String) -> String {
    let is_vowel = |c: char| -> bool {
        matches!(c, 'a' | 'e' | 'i' | 'o' | 'u')
    };

    // 1. Analysis Phase: Calculate frequencies and first indices
    let mut frequencies: HashMap<char, i32> = HashMap::new();
