    // 2. Sorting Phase: Sort the unique vowels based on criteria
    // Primary: Frequency (Descending)
    // Secondary: First Index (Ascending)
    unique_vowels.sort_by(|&a, &b| {
        let freq_a = frequencies[&a];
        let freq_b = frequencies[&b];

        // Compare frequencies (Descending: b vs a)
