fn char_to_index(c: char) -> Option<usize> {
    match c {
        'a' => Some(0),
        'e' => Some(1),
        'i' => Some(2),
        'o' => Some(3),
        'u' => Some(4),
        _ => None,
    }
}

fn index_to_char(i: usize) -> char {
    match i {
        0 => 'a',
        1 => 'e',
        2 => 'i',
        3 => 'o',
        4 => 'u',
        _ => unreachable!(),
    }
}

fn solve(s: String) -> String {
    let s_chars: Vec<char> = s.chars().collect();
    let n = s_chars.len();

    // Frequencies: [5] where index corresponds to vowel ('a' -> 0, 'u' -> 4)
    let mut frequencies = [0; 5];
    // First index: [5] initialized to usize::MAX (a value indicating not seen)
    let mut first_indices = [usize::MAX; 5];

    // 1. Analysis Phase
    for (i, &c) in s_chars.iter().enumerate() {
        if let Some(idx) = char_to_index(c) {
            // Calculate frequency
            frequencies[idx] += 1;

            // Record first index
            if first_indices[idx] == usize::MAX {
                first_indices[idx] = i;
            }
        }
    }

    // Identify unique vowels present (indices where frequency > 0)
    let mut present_vowel_indices: Vec<usize> = (0..5).filter(|&i| frequencies[i] > 0).collect();

    // 2. Sorting Phase: Sort the indices based on criteria
    // Primary: Frequency (Descending)
    // Secondary: First Index (Ascending)
    present_vowel_indices.sort_unstable_by(|&idx_a, &idx_b| {
        let freq_a = frequencies[idx_a];
        let freq_b = frequencies[idx_b];

        // Compare frequencies (Descending: B vs A)
        if freq_a != freq_b {
            // We want higher frequency first, so b compared to a
            freq_b.cmp(&freq_a)
        } else {
            // Frequencies are equal, compare first indices (Ascending: A vs B)
            let index_a = first_indices[idx_a];
            let index_b = first_indices[idx_b];
            index_a.cmp(&index_b)
        }
    });

    // 3. Construct the replacement sequence
    let mut replacement_sequence: Vec<char> = Vec::new();
    for &idx in &present_vowel_indices {
        let count = frequencies[idx];
        let vowel_char = index_to_char(idx);
        for _ in 0..count {
            replacement_sequence.push(vowel_char);
        }
    }

    // 4. Replacement Phase: Reconstruct the string
    let mut result = Vec::with_capacity(n);
    let mut seq_idx = 0;

    for &c in s_chars.iter() {
        if char_to_index(c).is_some() {
            // It's a vowel, replace with the next character from the sorted sequence
            if seq_idx < replacement_sequence.len() {
                result.push(replacement_sequence[seq_idx]);
                seq_idx += 1;
