use std::collections::HashMap;

fn solve(s: String) -> String {
    // Helper function to check for vowels
    let is_vowel = |c: char| -> bool {
        matches!(c, 'a' | 'e' | 'i' | 'o' | 'u')
    };

    // 1. Analysis Phase: Calculate frequencies and first indices
    let mut frequencies: HashMap<char, usize> = HashMap::new();
    let mut first_indices: HashMap<char, usize> = HashMap::new();

    for (i, c) in s.chars().enumerate() {
        if is_vowel(c) {
            // Calculate frequency
            *frequencies.entry(c).or_insert(0) += 1;

            // Record first index
            first_indices.entry(c).or_insert(i);
        }
    }

    // Get unique vowels present
    let mut unique_vowels: Vec<char> = frequencies.keys().cloned().collect();

    // 2. Sorting Phase: Sort the unique vowels based on criteria
    // Primary: Frequency (Descending)
    // Secondary: First Index (Ascending)
    unique_vowels.sort_by(|&a, &b| {
        // Get frequencies (guaranteed to exist)
        let freq_a = *frequencies.get(&a).unwrap();
        let freq_b = *frequencies.get(&b).unwrap();

        // Compare frequencies (Descending: B vs A)
        match freq_b.cmp(&freq_a) {
            std::cmp::Ordering::Equal => {
                // Frequencies are equal, compare first indices (Ascending: A vs B)
                let index_a = *first_indices.get(&a).unwrap();
                let index_b = *first_indices.get(&b).unwrap();
                index_a.cmp(&index_b)
            },
            other => other,
        }
    });

    // 3. Construct the replacement sequence
    let mut replacement_sequence: Vec<char> = Vec::new();
    for &vowel in &unique_vowels {
        let count = *frequencies.get(&vowel).unwrap();
        for _ in 0..count {
            replacement_sequence.push(vowel);
        }
    }

    // 4. Replacement Phase: Reconstruct the string
    let mut sequence_index = 0;
    let mut result: Vec<char> = Vec::new();

    for c in s.chars() {
        if is_vowel(c) {
            // Replace with the next character from the sorted sequence
            // We must ensure sequence_index is within bounds, which it should be 
            // because the total count of vowels matches the length of replacement_sequence.
            result.push(replacement_sequence[sequence_index]);
            sequence_index += 1;
        } else {
            // Keep consonant as is
            result.push(c);
        }
    }

    result.into_iter().collect()
}

